// Map ASCII character to glyph index (-1 if not found)
inline int bigfont_index(char c) {
  if (c >= '0' && c <= '9') return c - '0';
  switch(c) {
    case ',': return 10;
    case '.': return 11;
    case ' ': return 12;
    case 'K': return 13;
    case 'M': return 14;
    case '+': return 15;
    default:  return -1;
  }
}

